diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 02fea2eaf9d4..ed9d86deb6c3 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -14418,6 +14418,25 @@ class BoUpSLP::ShuffleInstructionBuilder final : public BaseShuffleAnalysis {
     /// Creates permutation of the single vector operand with the given mask, if
     /// it is not identity mask.
     Value *createShuffleVector(Value *V1, ArrayRef<int> Mask) {
+      // Check if this is a broadcast pattern (all elements are 0).
+      // If so, we need to ensure V1 is a vector. If it's a scalar,
+      // we need to create an insertelement first.
+      if (!Mask.empty() && ShuffleVectorInst::isZeroEltSplatMask(Mask, Mask.size())) {
+        // If V1 is not a vector type, we need to create an insertelement
+        // to put it into a vector first.
+        if (!V1->getType()->isVectorTy()) {
+          auto *VecTy = FixedVectorType::get(V1->getType(), Mask.size());
+          V1 = Builder.CreateInsertElement(PoisonValue::get(VecTy), V1,
+                                           Builder.getInt32(0));
+        } else if (isa<InsertElementInst>(V1)) {
+          // V1 is already an insertelement instruction. Make sure it's
+          // inserted before we create the shufflevector.
+          if (auto *I = dyn_cast<Instruction>(V1))
+            if (!I->getParent())
+              Builder.Insert(I);
+        }
+      }
+      
       if (Mask.empty())
         return V1;
       unsigned VF = Mask.size();
